// WF_MUSIC_GENERATE — Vertex AI Lyria music composition with per-project preferences.
// Pattern: fetch() + $env (n8n 2.8.4 task runner safe). Respects migration 014 music prefs.
// Updated S5 (CF07): music_enabled short-circuit, music_mood_override prompt injection,
// music_volume feeds ducking, claude-haiku-4-5-20251001 for mood analysis.

const input = $input.first().json;
const topicId = input.topic_id;
const shortForm = !!input.short_form;
const SUPABASE = $env.SUPABASE_URL;
const HEADERS_SUPA = { apikey: $env.SUPABASE_ANON_KEY, Authorization: `Bearer ${$env.SUPABASE_SERVICE_ROLE_KEY}`, 'Content-Type': 'application/json' };

async function fetchJson(url, opts = {}) {
  const res = await fetch(url, opts);
  if (!res.ok) throw new Error(`HTTP ${res.status}: ${await res.text()}`);
  return res.json();
}

if (!topicId) return [{ json: { success: false, error: 'topic_id required' } }];

// ── 1. Topic + project fetch (join project preferences)
const topicRows = await fetchJson(`${SUPABASE}/rest/v1/topics?id=eq.${topicId}&select=id,project_id,script_json,word_count,seo_title,production_register,register_era_detected`, { headers: HEADERS_SUPA });
const topic = topicRows?.[0];
if (!topic) return [{ json: { success: false, error: 'topic not found', topic_id: topicId } }];
if (!topic.script_json) return [{ json: { success: false, error: 'no script_json', topic_id: topicId } }];

const projectRows = await fetchJson(`${SUPABASE}/rest/v1/projects?id=eq.${topic.project_id}&select=music_enabled,music_volume,music_mood_override,music_source`, { headers: HEADERS_SUPA });
const project = projectRows?.[0] || {};
const musicEnabled = project.music_enabled !== false; // null/true → enabled
const musicVolume = Number(project.music_volume ?? (shortForm ? 0.08 : 0.12));
const moodOverride = project.music_mood_override || null;
const musicSource = project.music_source || 'lyria';

// ── Fetch production_register config (BPM + mood keywords)
let registerConfig = null;
let registerId = topic.production_register || null;
let registerEra = topic.register_era_detected || null;
if (registerId) {
  try {
    const rows = await fetchJson(`${SUPABASE}/rest/v1/production_registers?register_id=eq.${registerId}&select=config`, { headers: HEADERS_SUPA });
    registerConfig = rows?.[0]?.config || null;
  } catch (e) { console.warn('Register config fetch failed (non-fatal): ' + e.message); }
}
const registerBpmMin = registerConfig?.music_bpm_min || null;
const registerBpmMax = registerConfig?.music_bpm_max || null;
const registerMoodKeywords = registerConfig?.music_mood_keywords || null;

// Early exit if music disabled for this project
if (!musicEnabled) {
  return [{ json: { success: true, skipped: true, reason: 'music_disabled', topic_id: topicId, duck_volume: 0 } }];
}

// Library-source path: dashboard/user picks track from music_library; skip Lyria
if (musicSource === 'library') {
  return [{ json: { success: true, skipped: true, reason: 'library_source', topic_id: topicId, duck_volume: musicVolume.toFixed(2) } }];
}

// ── 2. Derive script timing
const scenes = Array.isArray(topic.script_json) ? topic.script_json : (topic.script_json?.scenes || []);
const scriptText = scenes.map(s => s.narration || s.narration_text || '').join(' ');
const wordCount = topic.word_count || scriptText.split(/\s+/).filter(Boolean).length;
const durationMinutes = Math.max(1, Math.ceil(wordCount / 150));
const clipsNeeded = Math.max(1, Math.ceil((durationMinutes * 60) / 30));

// ── 3. Mood profile via Claude Haiku 4.5 (cost-sensitive per S1-S4 convention)
let moodConstraint;
if (moodOverride) {
  moodConstraint = `The user has LOCKED the mood to: ${moodOverride}. Honor this — do not drift.`;
} else if (registerMoodKeywords && registerBpmMin && registerBpmMax) {
  moodConstraint = `Production register is ${registerId}${registerEra ? ' (era: ' + registerEra + ')' : ''}. The register prescribes mood keywords: ${registerMoodKeywords}. BPM MUST stay within ${registerBpmMin}-${registerBpmMax} BPM. Use these as hard constraints; derive specific instrumentation from the script emotional arc.`;
} else {
  moodConstraint = 'Derive mood from script emotional arc.';
}

const musicPrompt = [
  'You are a world-class film composer scoring cinematic background music for a YouTube video essay.',
  'Analyze this script and return a music generation profile.',
  '',
  moodConstraint,
  '',
  'REQUIREMENTS:',
  '- Film score quality: orchestral strings, emotive piano, atmospheric synth pads',
  '- Dynamic range: soft passages, building tension, emotional swells',
  '- Support narration: stay in mid-low frequency range, leave vocal space clear',
  '- NO lyrics, NO vocals, NO artist name references',
  '- Describe SOUND only: instruments, mood, tempo, energy, texture',
  '',
  `Script: ${wordCount} words, ${durationMinutes} minutes, needs ${clipsNeeded} × 30s clips`,
  '',
  `Script excerpt: ${scriptText.substring(0, 2000)}`,
  '',
  'Return ONLY this JSON (no markdown):',
  '{"genre":"","mood":"","bpm":0,"instruments":"","base_prompt":"","variation_prompts":["","",""],"energy_curve":""}'
].join('\n');

let musicProfile;
try {
  const aiResp = await fetchJson('https://api.anthropic.com/v1/messages', {
    method: 'POST',
    headers: { 'x-api-key': $env.ANTHROPIC_API_KEY, 'anthropic-version': '2023-06-01', 'content-type': 'application/json' },
    body: JSON.stringify({ model: 'claude-haiku-4-5-20251001', max_tokens: 1024, messages: [{ role: 'user', content: musicPrompt }] })
  });
  const text = aiResp.content?.[0]?.text || '{}';
  try { musicProfile = JSON.parse(text); }
  catch { const m = text.match(/\{[\s\S]*\}/); musicProfile = m ? JSON.parse(m[0]) : null; }
} catch (e) {
  musicProfile = null;
}

if (!musicProfile || !musicProfile.base_prompt) {
  musicProfile = {
    genre: 'cinematic', mood: moodOverride || 'contemplative', bpm: 80,
    instruments: 'orchestral strings, piano, subtle synth pads',
    base_prompt: `${moodOverride || 'cinematic'} orchestral underscore, emotional piano, subtle strings, 80 bpm`,
    variation_prompts: [], energy_curve: 'gradual swell'
  };
}

// Honor mood override by prepending to base_prompt if not already present
if (moodOverride && !musicProfile.base_prompt.toLowerCase().includes(moodOverride.toLowerCase())) {
  musicProfile.base_prompt = `${moodOverride} ${musicProfile.base_prompt}`;
}

// ── 4. GCP token + Lyria generation (existing infrastructure — kept intact)
let gcpToken;
try {
  const tokenResp = await fetchJson('http://gcp-token-service:3001/token');
  gcpToken = tokenResp.token || tokenResp.access_token;
} catch (e) {
  return [{ json: { success: false, error: 'GCP token service unavailable: ' + e.message, topic_id: topicId, duck_volume: musicVolume.toFixed(2) } }];
}

const gcpProject = $env.GCP_PROJECT || 'vision-gridai';
const gcpRegion = $env.GCP_REGION || 'us-central1';
const lyriaUrl = `https://${gcpRegion}-aiplatform.googleapis.com/v1/projects/${gcpProject}/locations/${gcpRegion}/publishers/google/models/lyria-002:predict`;

const prompts = [musicProfile.base_prompt, ...(musicProfile.variation_prompts || [])].filter(Boolean);
const clipPaths = [];

for (let i = 0; i < Math.min(clipsNeeded, Math.max(prompts.length, 1)); i++) {
  const prompt = prompts[i % prompts.length] || musicProfile.base_prompt;
  try {
    const resp = await fetchJson(lyriaUrl, {
      method: 'POST',
      headers: { Authorization: `Bearer ${gcpToken}`, 'Content-Type': 'application/json' },
      body: JSON.stringify({ instances: [{ prompt, duration_seconds: 30 }], parameters: { sample_count: 1 } })
    });
    const audioData = resp?.predictions?.[0]?.bytesBase64Encoded;
    if (audioData) {
      const clipPath = `/tmp/production/${topicId}/music_clip_${i}.wav`;
      const { execSync } = require('child_process');
      execSync(`mkdir -p /tmp/production/${topicId}`);
      require('fs').writeFileSync(clipPath, Buffer.from(audioData, 'base64'));
      clipPaths.push(clipPath);
    }
  } catch (e) {
    // continue on per-clip failure
  }
  if (i < clipsNeeded - 1) await new Promise(r => setTimeout(r, 5000));
}

if (clipPaths.length === 0) {
  return [{ json: { success: false, error: 'No music clips generated', topic_id: topicId, duck_volume: musicVolume.toFixed(2) } }];
}

// ── 5. Merge + loop (FFmpeg via host-side execSync; already working in prod)
const { execSync } = require('child_process');
const mergedPath = `/tmp/production/${topicId}/music_merged.mp3`;
try {
  if (clipPaths.length === 1) {
    execSync(`ffmpeg -y -i "${clipPaths[0]}" -c:a libmp3lame -b:a 192k "${mergedPath}"`, { timeout: 30000 });
  } else {
    const concatList = clipPaths.map(p => `file '${p}'`).join('\n');
    require('fs').writeFileSync(`/tmp/production/${topicId}/music_concat.txt`, concatList);
    execSync(`ffmpeg -y -f concat -safe 0 -i /tmp/production/${topicId}/music_concat.txt -c:a libmp3lame -b:a 192k "${mergedPath}"`, { timeout: 60000 });
  }
} catch (e) {
  return [{ json: { success: false, error: 'Music merge failed: ' + e.message, topic_id: topicId } }];
}

const targetDuration = durationMinutes * 60;
const loopedPath = `/tmp/production/${topicId}/music_final.mp3`;
try {
  execSync(`ffmpeg -y -stream_loop -1 -i "${mergedPath}" -t ${targetDuration} -c:a libmp3lame -b:a 192k "${loopedPath}"`, { timeout: 60000 });
} catch (e) {
  execSync(`cp "${mergedPath}" "${loopedPath}"`);
}

return [{ json: {
  success: true,
  topic_id: topicId,
  method: 'lyria_generation',
  model: 'lyria-002',
  mood_derived: musicProfile.mood,
  mood_override_applied: !!moodOverride,
  music_source: musicSource,
  clips_generated: clipPaths.length,
  clips_needed: clipsNeeded,
  music_path: loopedPath,
  duration_target: targetDuration,
  music_profile: musicProfile,
  duck_volume: musicVolume.toFixed(2)
}}];

